import{_ as e,o,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const s=JSON.parse('{"title":"G08: 業界地位與市佔率 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3189_景碩/20260423/G08_業界地位與市佔率_投資研究員.md","filePath":"審計報告庫/經營審計/3189_景碩/20260423/G08_業界地位與市佔率_投資研究員.md"}'),l={name:"審計報告庫/經營審計/3189_景碩/20260423/G08_業界地位與市佔率_投資研究員.md"};function i(d,a,_,n,c,h){return o(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="g08-業界地位與市佔率-投資研究員-審計報告" tabindex="-1">G08: 業界地位與市佔率 - 投資研究員 審計報告 <a class="header-anchor" href="#g08-業界地位與市佔率-投資研究員-審計報告" aria-label="Permalink to &quot;G08: 業界地位與市佔率 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>公司在當前競爭環境中的行業佔有率為何？是產業領銜者還是追隨者？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>景碩是全球第四大ABF載板供應商（市佔率約12%），僅次於Ibiden（30%）、欣興（20-25%）、AT&amp;S（15%），技術位階屬第二梯隊。BT載板領域則為全球最大供應商，市佔率約20-25%，超越日系廠商。整體載板產業集中度高（前五大佔&gt;70%），屬寡佔市場格局，進入壁壘極高。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A（良）。ABF載板全球第四名仍有上升空間（產能擴張+客戶認證深化中）；BT載板全球第一名已確認且短期難以被撼動。產業結構性進入壁壘（資本投入+客戶認證）保護了現有玩家地位。ABF載板市佔率從2023年8%增至2025年12%，擴張速度符合預期。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>全球ABF載板市佔率排名（2025年估算）：(1) Ibiden 30%（日本，技術領先1.5代，GPU主力供應商）(2) 欣興3037 22%（台灣，NVIDIA+AMD主力）(3) AT&amp;S 15%（奧地利，專注HPC網通）(4) 景碩3189 12%（台灣，BT第一+ABF追趕中）(5) 南電8046 8%（台灣，ABF低階主力）(6) 三星電機10-12%（韓國，集團內部供應）。全球BT載板排名（2025年）：(1) 景碩20-25%（台灣）(2) 三星電機15-18%（韓國）(3) Ibiden 12-15%（日本）(4) 深南電路12-15%（中國）。</p><p>產業地位趨勢分析：景碩在ABF的市佔率從2023年約8%提升至2025年12%，主要受惠NVIDIA CPU載板份額增長和Google TPU設計成功。但注意ABF載板市場2025-2030 CAGR約16.1%（Prismark數據），若景碩擴產速度跟不上市場成長，市佔率可能停滯。</p><p>景碩ABF載板市佔率擴張的驅動力來自：(1)NVIDIA CPU載板供貨率從5%升至50%, (2)Google TPU設計定案量產, (3)Broadcom ASIC載板設計中。最需關注的是景碩在NVIDIA新一代GPU載板（Rubin架構）的供應份額佔比變化，這是決定2027年市佔率能否突破15%的關鍵。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>景碩的產業地位呈現特色鮮明的雙軌格局——BT載板龍頭地位穩固（規模+良率優勢），ABF載板追趕者角色具上升動能（產能擴張+認證深化中）。從產業地位角度看，BT載板類似「現金牛」，ABF載板類似「追趕者」，晶碩光學則屬「探險型」。</p><p>最需關注的市佔率關鍵變數：2026年Google TPU v6和Broadcom ASIC出貨規模——若單一客戶開出單季&gt;30億元營收貢獻，景碩在ABF載板的市佔率有望在2027年達16-18%。反之，若因量產良率問題延遲，市佔率擴張將不及預期。</p><p>景碩2027年的市佔率目標為15-18%，但前提是ABF產能擴充按計劃進行且NVIDIA供貨率維持增長。若其中任一前提未達標，實際市佔率可能僅達13-14%，低於市場預期。</p><p>產業地位變化的關鍵驅動力：2026-2027年Google和Broadcom ASIC載板出貨量。若這兩個客戶總貢獻能達景碩營收的15-20%，將有效降低對NVIDIA依賴（從25-30%降至&lt;20%），同時帶動全球ABF載板市佔提升至15%+。建議每季追蹤ASIC客戶營收佔比的變化。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>優分析UAnalyze</code>: 全球ABF載板供應商市佔率排名（2025年）</li><li><code>IEK產業情報網</code>: 載板產業CAGR 16.1% (2025-2030)</li><li><code>Prismark Partners</code>: IC載板市場報告</li><li><code>法說會</code>: 景碩2026年3月法說會（BT載板全球第一大地位）</li><li><code>集邦科技TrendForce</code>: 全球IC載板產業鏈分析</li></ul>',18)])])}const p=e(l,[["render",i]]);export{s as __pageData,p as default};
